#include <stdio.h>
#include <cuda_runtime.h>

// CUDA kernel: each thread computes one element of the result
__global__ void vectorAdd(const float* A, const float* B, float* C, int n) {
 int i = threadIdx.x + blockIdx.x * blockDim.x;
 if (i < n) {
 C[i] = A[i] + B[i]; // Write result to device memory
 }
}

// Error checking macro for cleaner code
#define CUDA_CHECK(call) \
 do { \
 cudaError_t err = call; \
 if (err != cudaSuccess) { \
 fprintf(stderr, "CUDA error at %s:%d: %s\n", \
 __FILE__, __LINE__, cudaGetErrorString(err)); \
 exit(EXIT_FAILURE); \
 } \
 } while(0)

int main() {
 int n = 1024;
 size_t bytes = n * sizeof(float);

 // Allocate host memory (pageable)
 float *h_A = (float*)malloc(bytes);
 float *h_B = (float*)malloc(bytes);
 float *h_C = (float*)malloc(bytes);

 // Initialize input arrays
 for (int i = 0; i < n; i++) {
 h_A[i] = (float)i;
 h_B[i] = (float)(i * 2);
 }

 // Allocate device memory
 float *d_A, *d_B, *d_C;
 CUDA_CHECK(cudaMalloc(&d_A, bytes));
 CUDA_CHECK(cudaMalloc(&d_B, bytes));
 CUDA_CHECK(cudaMalloc(&d_C, bytes));

 // Copy input data from host to device (HostToDevice)
 CUDA_CHECK(cudaMemcpy(d_A, h_A, bytes, cudaMemcpyHostToDevice));
 CUDA_CHECK(cudaMemcpy(d_B, h_B, bytes, cudaMemcpyHostToDevice));

 // Launch kernel: calculate grid and block dimensions
 int threadsPerBlock = 256;
 int blocksPerGrid = (n + threadsPerBlock - 1) / threadsPerBlock;
 vectorAdd<<<blocksPerGrid, threadsPerBlock>>>(d_A, d_B, d_C, n);

 // Check for kernel launch errors
 CUDA_CHECK(cudaGetLastError());

 // Synchronize to ensure kernel completes before copying results
 CUDA_CHECK(cudaDeviceSynchronize());

 // Copy results from device to host (DeviceToHost)
 CUDA_CHECK(cudaMemcpy(h_C, d_C, bytes, cudaMemcpyDeviceToHost));

 // Verify results
 printf("First 5 results:\n");
 for (int i = 0; i < 5; i++) {
 printf(" C[%d] = %.1f (expected %.1f)\n", i, h_C[i], h_A[i] + h_B[i]);
 }

 // Cleanup: free both device and host memory
 CUDA_CHECK(cudaFree(d_A));
 CUDA_CHECK(cudaFree(d_B));
 CUDA_CHECK(cudaFree(d_C));
 free(h_A);
 free(h_B);
 free(h_C);

 printf("Vector addition completed successfully!\n");
 return 0;
}

