// Parallel reduction kernel using shared memory
// Each block computes its partial sum, then we sum block results on host
__global__ void sumReductionKernel(const float* d_input, float* d_blockSums, int n) {
 // Shared memory for reduction within block
 extern __shared__ float sdata[];

 int tid = threadIdx.x;
 int idx = blockIdx.x * blockDim.x + threadIdx.x;

 // Each thread loads one element into shared memory
 sdata[tid] = (idx < n) ? d_input[idx] : 0.0f;
 __syncthreads();

 // Tree-based reduction: halve stride each iteration
 for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
 if (tid < s) {
 // Add neighbor element
 sdata[tid] += sdata[tid + s];
 }
 // Synchronize before next reduction step
 __syncthreads();
 }

 // Thread 0 of block writes the block's partial sum to global memory
 if (tid == 0) {
 d_blockSums[blockIdx.x] = sdata[0];
 }
}

// Second kernel to reduce block sums into final single result
__global__ void finalReductionKernel(const float* d_blockSums, float* d_result, int numBlocks) {
 extern __shared__ float sdata[];
 int tid = threadIdx.x;

 // Load block sums into shared memory
 sdata[tid] = (tid < numBlocks) ? d_blockSums[tid] : 0.0f;
 __syncthreads();

 // Reduce in shared memory
 for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
 if (tid < s) {
 sdata[tid] += sdata[tid + s];
 }
 __syncthreads();
 }

 if (tid == 0) {
 *d_result = sdata[0];
 }
}

int main() {
 const int n = 1000000;
 const int blockSize = 256;
 int numBlocks = (n + blockSize - 1) / blockSize;

 printf("Array size: %d, Blocks: %d, Threads per block: %d\n", n, numBlocks, blockSize);

 // Host memory for final result
 float h_result = 0.0f;

 // Allocate and initialize input data on host
 float *h_input = (float*)malloc(n * sizeof(float));
 for (int i = 0; i < n; i++) {
 h_input[i] = 1.0f; // Sum should be n
 }

 // Device memory
 float *d_input, *d_blockSums, *d_result;
 CUDA_CHECK(cudaMalloc(&d_input, n * sizeof(float)));
 CUDA_CHECK(cudaMalloc(&d_blockSums, numBlocks * sizeof(float)));
 CUDA_CHECK(cudaMalloc(&d_result, sizeof(float)));

 // Copy input to device
 CUDA_CHECK(cudaMemcpy(d_input, h_input, n * sizeof(float), cudaMemcpyHostToDevice));

 // First kernel: compute partial sums per block
 int sharedMem = blockSize * sizeof(float);
 sumReductionKernel<<<numBlocks, blockSize, sharedMem>>>(d_input, d_blockSums, n);
 CUDA_CHECK(cudaGetLastError());
 CUDA_CHECK(cudaDeviceSynchronize());

 // If many blocks, do second reduction; otherwise sum on host
 if (numBlocks <= blockSize) {
 // Final reduction kernel
 finalReductionKernel<<<1, blockSize, sharedMem>>>(d_blockSums, d_result, numBlocks);
 } else {
 // For very large arrays, would iterate - simplified here
 printf("Note: Would need multiple reduction passes for %d blocks\n", numBlocks);
 // Sum block sums on host (simple approach)
 float *h_blockSums = (float*)malloc(numBlocks * sizeof(float));
 CUDA_CHECK(cudaMemcpy(h_blockSums, d_blockSums, numBlocks * sizeof(float), cudaMemcpyDeviceToHost));
 h_result = 0.0f;
 for (int i = 0; i < numBlocks; i++) {
 h_result += h_blockSums[i];
 }
 free(h_blockSums);
 }

 CUDA_CHECK(cudaGetLastError());
 CUDA_CHECK(cudaDeviceSynchronize());

 // Copy final result to host
 CUDA_CHECK(cudaMemcpy(&h_result, d_result, sizeof(float), cudaMemcpyDeviceToHost));

 printf("Sum = %.0f (expected: %d)\n", h_result, n);

 // Cleanup
 CUDA_CHECK(cudaFree(d_input));
 CUDA_CHECK(cudaFree(d_blockSums));
 CUDA_CHECK(cudaFree(d_result));
 free(h_input);

 return 0;
}

