// Kernel using atomicAdd for thread-safe accumulation
// WARNING: This serializes writes - use only for small datasets or as final step
__global__ void sumWithAtomic(float* d_data, float* d_result, int n) {
 int idx = blockIdx.x * blockDim.x + threadIdx.x;

 if (idx < n) {
 // atomicAdd ensures thread-safe read-modify-write
 // Only one thread can update d_result at a time
 atomicAdd(d_result, d_data[idx]);
 }
}

// Alternative: block-level atomic for better performance
__global__ void sumBlockAtomic(float* d_data, float* d_blockSums, int n) {
 extern __shared__ float sdata[];

 int tid = threadIdx.x;
 int idx = blockIdx.x * blockDim.x + threadIdx.x;

 // Load into shared memory and reduce
 sdata[tid] = (idx < n) ? d_data[idx] : 0.0f;
 __syncthreads();

 for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
 if (tid < s) {
 sdata[tid] += sdata[tid + s];
 }
 __synhreads();
 }

 // Only thread 0 uses atomicAdd - much fewer atomic operations
 if (tid == 0) {
 atomicAdd(d_blockSums, sdata[0]);
 }
}

int main() {
 const int n = 100000;
 const int blockSize = 256;
 const int numBlocks = (n + blockSize - 1) / blockSize;

 printf("Testing atomicAdd with %d elements\n", n);

 // Host result
 float h_result = 0.0f;

 // Allocate and initialize input
 float *h_data = (float*)malloc(n * sizeof(float));
 for (int i = 0; i < n; i++) {
 h_data[i] = 1.0f;
 }

 // Device memory
 float *d_data, *d_result;
 CUDA_CHECK(cudaMalloc(&d_data, n * sizeof(float)));
 CUDA_CHECK(cudaMalloc(&d_result, sizeof(float)));

 // Initialize result to 0 on device (CRITICAL!)
 CUDA_CHECK(cudaMemcpy(d_result, &h_result, sizeof(float), cudaMemcpyHostToDevice));

 // Copy input data
 CUDA_CHECK(cudaMemcpy(d_data, h_data, n * sizeof(float), cudaMemcpyHostToDevice));

 // Method 1: Pure atomicAdd (simple but slow for large n)
 // Uncomment to test:
 // sumWithAtomic<<<numBlocks, blockSize>>>(d_data, d_result, n);

 // Method 2: Block-level atomic (better performance)
 // Each block computes partial sum in shared memory, then one atomic per block
 float *d_blockSums;
 CUDA_CHECK(cudaMalloc(&d_blockSums, sizeof(float)));
 float h_blockSums_init = 0.0f;
 CUDA_CHECK(cudaMemcpy(d_blockSums, &h_blockSums_init, sizeof(float), cudaMemcpyHostToDevice));

 int sharedMem = blockSize * sizeof(float);
 sumBlockAtomic<<<numBlocks, blockSize, sharedMem>>>(d_data, d_blockSums, n);
 CUDA_CHECK(cudaGetLastError());
 CUDA_CHECK(cudaDeviceSynchronize());

 // Copy result back
 float h_final_result;
 CUDA_CHECK(cudaMemcpy(&h_final_result, d_blockSums, sizeof(float), cudaMemcpyDeviceToHost));

 printf("Sum with block-level atomicAdd: %.0f (expected: %d)\n", h_final_result, n);

 // Compare performance
 printf("\nNote: atomicAdd serializes threads - use for small n or final aggregation\n");
 printf("For large arrays, use parallel reduction instead\n");

 // Cleanup
 CUDA_CHECK(cudaFree(d_data));
 CUDA_CHECK(cudaFree(d_result));
 CUDA_CHECK(cudaFree(d_blockSums));
 free(h_data);

 return 0;
}
